-- updating Hotfixes.faction_template sql database to match the correct db2 file from build 68453 and populate sql data base as it was empty
USE hotfixes
DROP TABLE IF EXISTS `faction_template`;

CREATE TABLE `faction_template` (
  `ID` INT NOT NULL,
  `Faction` SMALLINT UNSIGNED NOT NULL,
  `Flags` INT NOT NULL,
  `FactionGroup` TINYINT UNSIGNED NOT NULL,
  `FriendGroup` TINYINT UNSIGNED NOT NULL,
  `EnemyGroup` TINYINT UNSIGNED NOT NULL,
  `Enemies1` SMALLINT UNSIGNED NOT NULL,
  `Enemies2` SMALLINT UNSIGNED NOT NULL,
  `Enemies3` SMALLINT UNSIGNED NOT NULL,
  `Enemies4` SMALLINT UNSIGNED NOT NULL,
  `Enemies5` SMALLINT UNSIGNED NOT NULL,
  `Enemies6` SMALLINT UNSIGNED NOT NULL,
  `Enemies7` SMALLINT UNSIGNED NOT NULL,
  `Enemies8` SMALLINT UNSIGNED NOT NULL,
  `Friend1` SMALLINT UNSIGNED NOT NULL,
  `Friend2` SMALLINT UNSIGNED NOT NULL,
  `Friend3` SMALLINT UNSIGNED NOT NULL,
  `Friend4` SMALLINT UNSIGNED NOT NULL,
  `Friend5` SMALLINT UNSIGNED NOT NULL,
  `Friend6` SMALLINT UNSIGNED NOT NULL,
  `Friend7` SMALLINT UNSIGNED NOT NULL,
  `Friend8` SMALLINT UNSIGNED NOT NULL,
  `VerifiedBuild` INT NOT NULL, 
CONSTRAINT `PK_factiontemplate` PRIMARY KEY (ID)
);


